import{_ as r,g as t,c as l,B as e}from"./chunks/framework.UqVR3kzU.js";const c=JSON.parse('{"title":"🛡️ 第三部分：生存法则与红线","description":"","frontmatter":{},"headers":[],"relativePath":"part3.md","filePath":"part3.md","lastUpdated":null}'),o={name:"part3.md"};function i(n,a,s,h,g,d){return t(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="🛡️-第三部分-生存法则与红线" tabindex="-1">🛡️ 第三部分：生存法则与红线 <a class="header-anchor" href="#🛡️-第三部分-生存法则与红线" aria-label="Permalink to &quot;🛡️ 第三部分：生存法则与红线&quot;">​</a></h1><h2 id="6.设计规范速查" tabindex="-1">6. 设计规范速查 <a class="header-anchor" href="#6.设计规范速查" aria-label="Permalink to &quot;6. 设计规范速查{#6.设计规范速查}&quot;">​</a></h2><h3 id="6.1快速入口" tabindex="-1">6.1 快速入口 <a class="header-anchor" href="#6.1快速入口" aria-label="Permalink to &quot;6.1 快速入口{#6.1快速入口}&quot;">​</a></h3><ul><li><strong>次级界面规范快速查看</strong>：<a href="https://pan.baidu.com/s/1u4CCGdo9l53-1OnOAsjWEw?pwd=hjwl" target="_blank" rel="noreferrer">百度网盘链接</a></li><li><strong>次级界面规范源文件及复用</strong>：<a href="https://mastergo.com/goto/S0EL8plA?page_id=184:5558&amp;file=187632526699818" target="_blank" rel="noreferrer">火炬视觉整理（Mastergo，进入链接后可创建副本，方便在自己的账号内使用）</a></li></ul><h3 id="6.2移动端基础尺寸警戒线" tabindex="-1">6.2 移动端基础尺寸警戒线 <a class="header-anchor" href="#6.2移动端基础尺寸警戒线" aria-label="Permalink to &quot;6.2 移动端基础尺寸警戒线{#6.2移动端基础尺寸警戒线}&quot;">​</a></h3><ul><li><strong>一级页面</strong>：定制化设计，遵守基础尺寸规范，不要过大/过小，对照产品文档，我司使用750*1624px，1px=0.5pt，具体设计规范可参考“设计规范速查”。</li><li><strong>常见新人雷区（必看）</strong>： <ul><li>❌ <strong>字号过小</strong>：正文不要小于 20px，避免看不清。</li><li>❌ <strong>点击区过小</strong>：安卓/iOS 热区不得小于 44x44px，否则会影响客户操作体验或误触。</li><li>❌ <strong>忘记空状态</strong>：列表无数据时必须配图+提示文案（如“暂无数据，去逛逛”）。</li><li>❌ <strong>对齐偏差</strong>：注意像素级精准，避免出现色值错误、文字错别字。</li></ul></li></ul><h2 id="7.协作与沟通铁律" tabindex="-1">7. 协作与沟通铁律 <a class="header-anchor" href="#7.协作与沟通铁律" aria-label="Permalink to &quot;7. 协作与沟通铁律{#7.协作与沟通铁律}&quot;">​</a></h2><h3 id="7.1设计评审话术模板" tabindex="-1">7.1 设计评审话术模板 <a class="header-anchor" href="#7.1设计评审话术模板" aria-label="Permalink to &quot;7.1 设计评审话术模板{#7.1设计评审话术模板}&quot;">​</a></h3><ul><li><strong>少说</strong>：“我觉得不好看。”</li><li><strong>多说</strong>：“从用户角度，这个设计可能导致XX操作不便；从开发角度，这样调整能避免增加额外工作量。”</li></ul><h3 id="7.2与前端开发的“互译词典”" tabindex="-1">7.2 与前端开发的“互译词典” <a class="header-anchor" href="#7.2与前端开发的“互译词典”" aria-label="Permalink to &quot;7.2 与前端开发的“互译词典”{#7.2与前端开发的“互译词典”}&quot;">​</a></h3><ul><li><strong>开发说“无法实现”时</strong>：先问清是逻辑限制？还是成本过高？亦或是需求对接问题？提前与产品和开发人员共同探讨需求文档，不硬刚，不盲从。</li><li><strong>尊重技术边界</strong>：设计方案需考虑技术可行性、开发成本，避免无效设计。</li><li><strong>文件管理</strong>：设计稿按规范命名、归档，及时更新版本，避免出现“旧版误用”；需协同设计的文件应共享给相关人员并设置对应权限。</li></ul><h2 id="8.职业素养与持续学习" tabindex="-1">8. 职业素养与持续学习 <a class="header-anchor" href="#8.职业素养与持续学习" aria-label="Permalink to &quot;8. 职业素养与持续学习{#8.职业素养与持续学习}&quot;">​</a></h2><ul><li><strong>产品至上</strong>：所有设计围绕“用户体验”和“产品需求文档”，不盲目追求视觉美观，不额外添加功能，不缺少必要功能。</li><li><strong>务实落地</strong>：注重开发的可实现程度。</li><li><strong>细节控</strong>：杜绝低级错误。</li><li><strong>持续学习</strong>：主动关注设计趋势、行业案例，定期总结沉淀。</li></ul>',13)])])}const p=r(o,[["render",i]]);export{c as __pageData,p as default};
